CREATE VIEW INFORMATION_SCHEMA.tables\n(\n    `table_catalog` String,\n    `table_schema` String,\n    `table_name` String,\n    `table_type` String,\n    `table_rows` Nullable(UInt64),\n    `data_length` Nullable(UInt64),\n    `index_length` Nullable(UInt64),\n    `table_collation` Nullable(String),\n    `table_comment` Nullable(String),\n    `TABLE_CATALOG` String,\n    `TABLE_SCHEMA` String,\n    `TABLE_NAME` String,\n    `TABLE_TYPE` String,\n    `TABLE_ROWS` Nullable(UInt64),\n    `DATA_LENGTH` Nullable(UInt64),\n    `TABLE_COLLATION` Nullable(String),\n    `TABLE_COMMENT` Nullable(String)\n)\nSQL SECURITY INVOKER\nAS SELECT\n    database AS table_catalog,\n    database AS table_schema,\n    name AS table_name,\n    multiIf(is_temporary, \'LOCAL TEMPORARY\', engine LIKE \'%View\', \'VIEW\', engine LIKE \'System%\', \'SYSTEM VIEW\', has_own_data = 0, \'FOREIGN TABLE\', \'BASE TABLE\') AS table_type,\n    total_rows AS table_rows,\n    total_bytes AS data_length,\n    sum(((p.primary_key_size + p.marks_bytes) + p.secondary_indices_compressed_bytes) + p.secondary_indices_marks_bytes) AS index_length,\n    \'utf8mb4_0900_ai_ci\' AS table_collation,\n    comment AS table_comment,\n    table_catalog AS TABLE_CATALOG,\n    table_schema AS TABLE_SCHEMA,\n    table_name AS TABLE_NAME,\n    table_type AS TABLE_TYPE,\n    table_rows AS TABLE_ROWS,\n    data_length AS DATA_LENGTH,\n    table_collation AS TABLE_COLLATION,\n    table_comment AS TABLE_COMMENT\nFROM system.tables AS t\nLEFT JOIN system.parts AS p ON (t.database = p.database) AND (t.name = p.`table`)\nGROUP BY\n    t.database,\n    t.name,\n    t.is_temporary,\n    t.engine,\n    t.has_own_data,\n    t.total_rows,\n    t.total_bytes,\n    t.comment
